Below is a single self-contained HTML file that visualizes a singly linked list. It includes:

- A canvas-like SVG rendering of nodes as boxes with arrows.
- Controls for: insert at head, insert at tail, delete by value, and search by value.
- Visual animations: inserting fades/appears, deleting highlights and removes, searching steps through nodes and highlights the found node.
- Graceful handling of empty list (shows "Empty list", buttons disabled appropriately).
- Input validation and small status messages.

Copy the entire content into a file (for example, linked_list.html) and open it in a modern browser.

```html
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <title>Singly Linked List Visualizer</title>
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <style>
    :root{
      --bg:#f7fafc;
      --card:#ffffff;
      --muted:#6b7280;
      --accent:#2563eb;
      --danger:#dc2626;
      --success:#16a34a;
      --node:#111827;
      --arrow:#374151;
    }
    html,body{
      height:100%;
      margin:0;
      font-family:system-ui,-apple-system,Segoe UI,Roboto,"Helvetica Neue",Arial;
      background:linear-gradient(180deg,#eef2ff 0%,var(--bg) 40%);
      color:var(--node);
    }
    .wrap{
      max-width:1000px;
      margin:28px auto;
      padding:20px;
      background:var(--card);
      border-radius:12px;
      box-shadow:0 8px 30px rgba(15,23,42,0.08);
      border:1px solid rgba(15,23,42,0.04);
    }
    header{
      display:flex;
      align-items:center;
      justify-content:space-between;
      gap:12px;
      margin-bottom:18px;
    }
    h1{margin:0;font-size:18px;}
    p.lead{margin:0;color:var(--muted);font-size:13px}
    .controls{
      display:flex;
      gap:8px;
      flex-wrap:wrap;
      margin-bottom:14px;
      align-items:center;
    }
    .controls input[type="text"]{
      padding:8px 10px;
      border-radius:8px;
      border:1px solid #e6e9ee;
      width:160px;
    }
    .controls button{
      padding:9px 12px;
      border-radius:8px;
      border:1px solid rgba(15,23,42,0.06);
      background:linear-gradient(180deg,white,#f8fafc);
      cursor:pointer;
      box-shadow:0 2px 6px rgba(2,6,23,0.04);
    }
    .controls button.primary{
      background:linear-gradient(180deg,var(--accent),#1e40af);
      color:white;
      border:none;
    }
    .controls button.danger{
      background:linear-gradient(180deg,var(--danger),#991b1b);
      color:white;
      border:none;
    }
    .controls button:disabled{opacity:0.5;cursor:not-allowed}
    .status{
      margin-left:auto;
      color:var(--muted);
      font-size:13px;
    }
    .canvasWrap{
      border-radius:10px;
      background:linear-gradient(180deg,rgba(99,102,241,0.03),rgba(99,102,241,0.01));
      padding:18px;
      min-height:200px;
      display:flex;
      align-items:center;
      justify-content:center;
      position:relative;
      overflow:auto;
    }
    .emptyHint{
      color:var(--muted);
      font-size:14px;
      display:flex;
      gap:10px;
      align-items:center;
    }
    svg.nodeSvg{width:100%;height:240px;overflow:visible}
    .nodeRect{
      rx:8; ry:8;
      fill:white;
      stroke:#d1d5db;
      stroke-width:1;
      filter:drop-shadow(0 6px 12px rgba(2,6,23,0.06));
    }
    .nodeValue{
      font-weight:600;
      font-size:13px;
      fill:var(--node);
    }
    .nodeLabel{
      font-size:11px;
      fill:var(--muted);
    }
    .arrow{
      stroke:var(--arrow);
      fill:none;
      stroke-width:2;
      marker-end:url(#arrowhead);
      opacity:0.95;
    }
    .highlight{
      stroke: #fb923c;
      stroke-width:2.5;
      box-shadow:0 0 10px rgba(251,146,60,0.2);
    }
    .found{
      stroke:var(--success);
      stroke-width:3;
      filter: drop-shadow(0 6px 12px rgba(16,185,129,0.08));
    }
    .fade-in{
      animation:fadein .28s ease both;
    }
    .fade-out{
      animation:fadeout .28s ease both;
    }
    @keyframes fadein{
      from{opacity:0; transform:translateY(-6px) scale(0.98)}
      to{opacity:1; transform:none}
    }
    @keyframes fadeout{
      from{opacity:1; transform:none}
      to{opacity:0; transform:translateY(-6px) scale(0.98)}
    }
    footer{margin-top:12px;color:var(--muted);font-size:13px;}
    .small{font-size:12px;color:var(--muted)}
    .btn-inline{
      padding:6px 8px;border-radius:6px;border:1px solid #e6e9ee;background:white;font-size:13px;
    }
    @media (max-width:640px){
      .controls input[type="text"]{width:120px}
    }
  </style>
</head>
<body>
  <div class="wrap" role="application" aria-label="Singly linked list visualizer">
    <header>
      <div>
        <h1>Singly Linked List Visualizer</h1>
        <p class="lead">Insert head/tail, delete by value, and search with step-by-step highlighting.</p>
      </div>
      <div class="status" id="status">Size: 0</div>
    </header>

    <div class="controls" aria-hidden="false">
      <input id="valueInput" type="text" placeholder="Value (string or number)" aria-label="Node value">
      <button id="insertHeadBtn" class="primary">Insert Head</button>
      <button id="insertTailBtn" class="primary">Insert Tail</button>
      <button id="deleteBtn" class="danger">Delete by Value</button>
      <input id="searchInput" type="text" placeholder="Search value" aria-label="Search value">
      <button id="searchBtn" class="btn-inline">Search</button>
      <button id="clearBtn" title="Clear list">Clear</button>
    </div>

    <div class="canvasWrap" id="canvasWrap" aria-live="polite">
      <!-- SVG will be injected here -->
    </div>

    <footer>
      <span class="small">Tip: Use simple values. The visual lays out nodes horizontally; it scrolls if too wide.</span>
    </footer>
  </div>

  <script>
    // Simple singly linked list model and SVG renderer
    (function(){
      const canvasWrap = document.getElementById('canvasWrap');
      const status = document.getElementById('status');
      const valueInput = document.getElementById('valueInput');
      const insertHeadBtn = document.getElementById('insertHeadBtn');
      const insertTailBtn = document.getElementById('insertTailBtn');
      const deleteBtn = document.getElementById('deleteBtn');
      const searchInput = document.getElementById('searchInput');
      const searchBtn = document.getElementById('searchBtn');
      const clearBtn = document.getElementById('clearBtn');

      let list = []; // array of node values, index0 = head
      let animating = false;
      let nodeIdCounter = 1;

      function updateStatus(){
        status.textContent = 'Size: ' + list.length;
      }

      function createSVG(){
        // create a fresh SVG
        const svgns = "http://www.w3.org/2000/svg";
        const svg = document.createElementNS(svgns, 'svg');
        svg.setAttribute('class','nodeSvg');
        svg.setAttribute('aria-label','Linked list diagram');
        svg.setAttribute('role','img');
        svg.setAttribute('width','100%');
        svg.setAttribute('height','220');
        svg.setAttribute('viewBox','0 0 1000 220');
        // defs arrowhead
        const defs = document.createElementNS(svgns,'defs');
        defs.innerHTML = '<marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto"><path d="M0,0 L10,3.5 L0,7 z" fill="#374151" /></marker>';
        svg.appendChild(defs);
        return svg;
      }

      function render(){
        canvasWrap.innerHTML = '';
        if(list.length === 0){
          const empty = document.createElement('div');
          empty.className = 'emptyHint';
          empty.innerHTML = '<svg width="36" height="36" viewBox="0 0 24 24" fill="none" style="opacity:0.9;margin-right:6px"><path d="M3 7a2 2 0 0 1 2-2h14" stroke="#9ca3af" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/><path d="M7 7v11a2 2 0 0 0 2 2h6a2 2 0 0 0 2-2V7" stroke="#9ca3af" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/><path d="M10 3v4" stroke="#9ca3af" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg><div><strong>Empty list</strong><div style="color:var(--muted);font-size:13px">Insert nodes at head or tail to get started</div></div>';
          canvasWrap.appendChild(empty);
          updateStatus();
          updateControls();
          return;
        }

        const svg = createSVG();
        const svgns = "http://www.w3.org/2000/svg";

        // layout variables
        const padding = 20;
        const nodeW = 84;
        const nodeH = 46;
        const spacing = 28;
        const totalW = list.length * nodeW + (list.length - 1) * spacing + padding*2;
        const viewW = Math.max(1000, totalW);
        svg.setAttribute('viewBox','0 0 ' + viewW + ' 220');

        // draw nodes left-to-right
        const startX = padding;
        const y = 60;

        list.forEach((valObj, i) => {
          const x = startX + i * (nodeW + spacing);
          // group
          const g = document.createElementNS(svgns,'g');
          g.setAttribute('class','nodeGroup fade-in');
          g.setAttribute('data-index', i);
          g.setAttribute('transform','translate(' + x + ',' + y + ')');

          // rectangle
          const rect = document.createElementNS(svgns,'rect');
          rect.setAttribute('width', nodeW);
          rect.setAttribute('height', nodeH);
          rect.setAttribute('class','nodeRect');
          rect.setAttribute('rx','8');
          rect.setAttribute('ry','8');
          rect.setAttribute('fill','white');
          rect.setAttribute('id','nodeRect-' + valObj.id);
          // value text
          const txt = document.createElementNS(svgns,'text');
          txt.setAttribute('x', nodeW/2);
          txt.setAttribute('y', nodeH/2 + 5);
          txt.setAttribute('text-anchor','middle');
          txt.setAttribute('class','nodeValue');
          txt.textContent = valObj.value;

          // small label "head" or "tail"
          if(i===0){
            const lbl = document.createElementNS(svgns,'text');
            lbl.setAttribute('x', nodeW/2);
            lbl.setAttribute('y', -8);
            lbl.setAttribute('text-anchor','middle');
            lbl.setAttribute('class','nodeLabel');
            lbl.textContent = 'HEAD';
            g.appendChild(lbl);
          }
          if(i===list.length-1){
            const lbl2 = document.createElementNS(svgns,'text');
            lbl2.setAttribute('x', nodeW/2);
            lbl2.setAttribute('y', nodeH + 20);
            lbl2.setAttribute('text-anchor','middle');
            lbl2.setAttribute('class','nodeLabel');
            lbl2.textContent = 'TAIL';
            g.appendChild(lbl2);
          }

          g.appendChild(rect);
          g.appendChild(txt);
          svg.appendChild(g);

          // arrow to next
          if(i < list.length - 1){
            const arrow = document.createElementNS(svgns,'path');
            const sx = x + nodeW;
            const sy = y + nodeH/2;
            const ex = x + nodeW + spacing;
            const ey = sy;
            // simple horizontal arrow with slight curve
            const d = `M ${sx} ${sy} C ${sx+10} ${sy} ${ex-10} ${ey} ${ex} ${ey}`;
            arrow.setAttribute('d', d);
            arrow.setAttribute('class','arrow');
            arrow.setAttribute('fill','none');
            svg.appendChild(arrow);
          }
        });

        canvasWrap.appendChild(svg);
        updateStatus();
        updateControls();
        // ensure newly created content is visible (scroll to rightmost for tail insert)
        requestAnimationFrame(()=> {
          canvasWrap.scrollLeft = canvasWrap.scrollWidth;
        });
      }

      function updateControls(){
        // disable controls if animating
        const disabled = animating;
        insertHeadBtn.disabled = disabled;
        insertTailBtn.disabled = disabled;
        deleteBtn.disabled = disabled || list.length === 0;
        searchBtn.disabled = disabled || list.length === 0;
        clearBtn.disabled = disabled || list.length === 0;
      }

      function makeNode(value){
        return { value: String(value), id: nodeIdCounter++ };
      }

      // operations
      function insertHead(value){
        if(animating) return;
        const node = makeNode(value);
        animating = true;
        list.unshift(node);
        render();
        // small visual clue (flash head)
        setTimeout(()=> {
          highlightIndex(0, 'found', 600).then(()=> { animating = false; updateControls(); });
        }, 80);
      }

      function insertTail(value){
        if(animating) return;
        const node = makeNode(value);
        animating = true;
        list.push(node);
        render();
        setTimeout(()=> {
          highlightIndex(list.length-1, 'found', 600).then(()=> { animating = false; updateControls(); });
        }, 80);
      }

      function deleteByValue(value){
        if(animating || list.length===0) return;
        animating = true;
        // sequential walk to find first occurrence
        let i = 0;
        function step(){
          if(i >= list.length){
            // not found
            flashMessage('Value not found', 'danger');
            animating = false;
            updateControls();
            return;
          }
          highlightIndex(i, 'highlight', 500).then(()=> {
            if(list[i].value === value){
              // found; flash then remove
              highlightIndex(i, 'found', 700).then(()=> {
                // remove and re-render with fade-out animation on removed rect
                const removedId = list[i].id;
                list.splice(i,1);
                render();
                flashMessage('Deleted first occurrence', 'success');
                animating = false;
                updateControls();
              });
            } else {
              i++;
              step();
            }
          });
        }
        step();
      }

      function searchByValue(value){
        if(animating || list.length===0) return;
        animating = true;
        let i = 0;
        function step(){
          if(i >= list.length){
            flashMessage('Value not found', 'danger');
            animating = false;
            updateControls();
            return;
          }
          highlightIndex(i, 'highlight', 500).then(()=> {
            if(list[i].value === value){
              highlightIndex(i, 'found', 900).then(()=> {
                flashMessage('Value found', 'success');
                animating = false;
                updateControls();
              });
            } else {
              i++;
              step();
            }
          });
        }
        step();
      }

      // helper: highlight node at index; type = 'highlight' or 'found'; duration ms
      function highlightIndex(index, type, duration){
        return new Promise(resolve => {
          const svg = canvasWrap.querySelector('svg');
          if(!svg) { resolve(); return; }
          const g = svg.querySelector('g[data-index="' + index + '"]');
          if(!g){ resolve(); return; }
          const rect = g.querySelector('rect');
          const origStroke = rect.getAttribute('stroke') || '#d1d5db';
          const origWidth = rect.getAttribute('stroke-width') || '1';
          if(type === 'highlight'){
            rect.style.transition = 'stroke 160ms, stroke-width 160ms, filter 160ms';
            rect.setAttribute('stroke','#fb923c');
            rect.setAttribute('stroke-width','2.6');
            // subtle scale
            g.style.transformOrigin = 'center';
            g.style.transition = 'transform 160ms';
            g.style.transform = 'translateY(-6px)';
            setTimeout(()=>{},20);
            setTimeout(()=> {
              rect.setAttribute('stroke', origStroke);
              rect.setAttribute('stroke-width', origWidth);
              g.style.transform = '';
              resolve();
            }, duration);
          } else if(type === 'found'){
            rect.style.transition = 'stroke 160ms, stroke-width 160ms, filter 160ms';
            rect.setAttribute('stroke','#16a34a');
            rect.setAttribute('stroke-width','3');
            g.style.transformOrigin = 'center';
            g.style.transition = 'transform 200ms';
            g.style.transform = 'translateY(-6px)';
            setTimeout(()=> {
              rect.setAttribute('stroke', origStroke);
              rect.setAttribute('stroke-width', origWidth);
              g.style.transform = '';
              resolve();
            }, duration);
          } else {
            resolve();
          }
        });
      }

      function flashMessage(text, type){
        const prev = document.getElementById('tempMsg');
        if(prev) prev.remove();
        const span = document.createElement('span');
        span.id = 'tempMsg';
        span.textContent = text;
        span.style.position = 'absolute';
        span.style.right = '16px';
        span.style.top = '12px';
        span.style.padding = '8px 10px';
        span.style.borderRadius = '8px';
        span.style.fontSize = '13px';
        span.style.boxShadow = '0 6px 16px rgba(2,6,23,0.06)';
        span.style.background = (type==='success') ? '#ecfdf5' : (type==='danger' ? '#fff1f2' : '#eef2ff');
        span.style.color = (type==='success') ? '#065f46' : (type==='danger' ? '#7f1d1d' : '#1e3a8a');
        span.style.border = '1px solid rgba(2,6,23,0.04)';
        span.style.zIndex = 40;
        canvasWrap.appendChild(span);
        setTimeout(()=> {
          span.style.opacity = '0';
          span.style.transition = 'opacity 500ms';
          setTimeout(()=> span.remove(), 600);
        }, 1200);
      }

      // wire up events
      insertHeadBtn.addEventListener('click', ()=> {
        const v = valueInput.value.trim();
        if(v === '') { valueInput.focus(); return; }
        insertHead(v);
        valueInput.value = '';
        valueInput.focus();
      });
      insertTailBtn.addEventListener('click', ()=> {
        const v = valueInput.value.trim();
        if(v === '') { valueInput.focus(); return; }
        insertTail(v);
        valueInput.value = '';
        valueInput.focus();
      });
      deleteBtn.addEventListener('click', ()=> {
        const v = valueInput.value.trim();
        if(v === '') { valueInput.focus(); return; }
        deleteByValue(v);
        valueInput.value = '';
        valueInput.focus();
      });
      searchBtn.addEventListener('click', ()=> {
        const v = searchInput.value.trim();
        if(v === '') { searchInput.focus(); return; }
        searchByValue(v);
        searchInput.value = '';
      });
      clearBtn.addEventListener('click', ()=> {
        if(animating) return;
        if(list.length===0) return;
        list = [];
        render();
        flashMessage('List cleared', 'success');
      });

      // keyboard shortcuts: Enter in valueInput => insertTail; Ctrl+Enter => insertHead
      valueInput.addEventListener('keydown', (e)=>{
        if(e.key === 'Enter'){
          if(e.ctrlKey || e.metaKey) insertHeadBtn.click();
          else insertTailBtn.click();
        }
      });
      // initial render
      render();

      // expose nothing global
    })();
  </script>
</body>
</html>
```

If you want any additional features (step speed control, doubly linked list, array-backed view, exporting the list), tell me which and I'll update the file.

Below is a single self-contained HTML file. Save it as something like linked_list_viz.html and open it in your browser. It provides:

- A visual singly linked list: nodes shown as boxes with "value" and an arrow to the next node.
- Controls to insert at head, insert at tail, delete by value, and search by value.
- Smooth animations for node creation, deletion, and search traversal; found node is highlighted.
- Graceful handling of empty list (shows a placeholder message).
- Simple undo possibility via re-rendering; code is commented so you can modify easily.

Copy the entire content into a file and open it.

<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8" />
<title>Singly Linked List Visualizer</title>
<meta name="viewport" content="width=device-width,initial-scale=1" />
<style>
  :root{
    --bg:#f6f8fb;
    --panel:#ffffff;
    --accent:#2b7cff;
    --accent-2:#0ea5a3;
    --text:#0f1724;
    --muted:#6b7280;
    --danger:#ef4444;
    --success:#16a34a;
    --node-bg:#ffffff;
    --node-border:#d1d5db;
    --arrow:#9ca3af;
  }
  html,body{height:100%;}
  body{
    margin:0;
    font-family:Inter, ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
    background:linear-gradient(180deg,#f8fafc 0%, #f1f5f9 100%);
    color:var(--text);
    padding:20px;
    box-sizing:border-box;
  }
  .container{
    max-width:1100px;
    margin:0 auto;
  }
  h1{
    margin:0 0 10px 0;
    font-size:20px;
  }
  .card{
    background:var(--panel);
    border-radius:10px;
    box-shadow:0 6px 18px rgba(15,23,36,0.06);
    padding:18px;
    margin-bottom:18px;
  }
  .controls{
    display:flex;
    gap:12px;
    align-items:center;
    flex-wrap:wrap;
  }
  .controls input[type="text"]{
    padding:8px 10px;
    border-radius:8px;
    border:1px solid #e5e7eb;
    width:140px;
    outline:none;
    font-size:14px;
  }
  .controls button{
    padding:8px 12px;
    background:var(--accent);
    border:none;
    color:white;
    border-radius:8px;
    font-weight:600;
    cursor:pointer;
    box-shadow:0 6px 14px rgba(43,124,255,0.14);
  }
  .controls button.ghost{
    background:transparent;
    color:var(--accent);
    border:1px solid rgba(43,124,255,0.12);
    box-shadow:none;
  }
  .controls button.danger{
    background:var(--danger);
    box-shadow:0 6px 14px rgba(239,68,68,0.14);
  }
  .controls .small{
    padding:6px 8px;
    font-size:13px;
  }
  #canvas{
    margin-top:18px;
    min-height:140px;
    background:linear-gradient(180deg, rgba(255,255,255,0.6), rgba(255,255,255,0.4));
    border-radius:8px;
    border:1px dashed #e6eef8;
    position:relative;
    overflow:auto;
    padding:20px;
  }

  /* Node visuals */
  .list-row{
    display:flex;
    gap:18px;
    align-items:center;
    padding-bottom:12px;
    padding-top:6px;
  }
  .node{
    display:flex;
    align-items:center;
    gap:6px;
    background:var(--node-bg);
    border-radius:8px;
    padding:10px;
    border:2px solid var(--node-border);
    min-width:120px;
    box-sizing:border-box;
    position:relative;
    transition:transform 300ms ease, box-shadow 200ms ease, border-color 200ms ease;
  }
  .node .value{
    font-weight:700;
    min-width:40px;
    text-align:center;
    font-size:15px;
  }
  .node .meta{
    font-size:12px;
    color:var(--muted);
  }
  .arrow{
    width:40px;
    height:18px;
    display:flex;
    align-items:center;
    justify-content:center;
    color:var(--arrow);
    font-weight:700;
    user-select:none;
  }

  /* Highlights */
  .node.searching{
    transform:translateY(-6px) scale(1.02);
    box-shadow:0 10px 30px rgba(43,124,255,0.12);
    border-color:rgba(43,124,255,0.5);
  }
  .node.found{
    background:linear-gradient(90deg,#fff7ed, #fffbeb);
    border-color:rgba(250,204,21,0.6);
    box-shadow:0 10px 30px rgba(250,204,21,0.08);
  }
  .node.removing{
    opacity:0;
    transform:translateY(8px) scale(0.96);
  }

  /* Placeholder when empty */
  .empty{
    display:flex;
    align-items:center;
    justify-content:center;
    height:120px;
    color:var(--muted);
    gap:10px;
    font-size:15px;
  }

  /* small footer controls */
  .footer{
    display:flex;
    justify-content:space-between;
    align-items:center;
    gap:10px;
    margin-top:10px;
  }
  .muted{
    color:var(--muted);
    font-size:13px;
  }

  /* Responsive */
  @media (max-width:720px){
    .node{min-width:100px;}
    .controls input[type="text"]{width:110px;}
  }
</style>
</head>
<body>
<div class="container">
  <h1>Singly Linked List Visualizer</h1>
  <div class="card">
    <div class="controls">
      <input id="inputValue" type="text" placeholder="Value (string/number)" />
      <button id="insertHead" title="Insert at head">Insert Head</button>
      <button id="insertTail" title="Insert at tail">Insert Tail</button>
      <button id="deleteValue" class="danger" title="Delete by value">Delete Value</button>
      <button id="searchValue" class="ghost" title="Search for a value">Search</button>
      <button id="clearAll" class="ghost small" title="Clear entire list">Clear</button>
      <div style="flex:1"></div>
      <div class="muted">Tip: use short values for nicer layout</div>
    </div>

    <div id="canvas" aria-live="polite">
      <!-- Visual list will be rendered here -->
      <div class="empty" id="emptyState">
        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" style="opacity:0.9">
          <path d="M3 6h18" stroke="#cbd5e1" stroke-width="1.6" stroke-linecap="round"/>
          <path d="M6 9h12v9a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2V9z" stroke="#e2e8f0" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/>
          <path d="M9 3h6v4H9z" stroke="#e2e8f0" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/>
        </svg>
        The list is empty — insert nodes to get started.
      </div>
    </div>

    <div class="footer">
      <div class="muted">Nodes are shown left-to-right from head to tail</div>
      <div class="muted">Animation plays during operations</div>
    </div>
  </div>

  <div class="card">
    <div style="font-size:13px;color:var(--muted)">
      Implementation notes: This is an in-memory singly linked list represented as JS objects.
      The visualizer animates traversal during search and deletion. Deleting a value removes the first matching node.
    </div>
  </div>
</div>

<script>
/*
  Singly Linked List Visualizer
  - Node: { value: string, next: Node|null, id: number }
  - list: head reference
  Simple operations implemented: insertHead, insertTail, deleteValue (first occurrence), searchValue
  Visual rendering in DOM with simple animations.
*/

(function(){
  let nodeIdCounter = 1;
  function makeNode(value){
    return { value: String(value), next: null, id: nodeIdCounter++ };
  }

  let head = null;

  // DOM elements
  const canvas = document.getElementById('canvas');
  const emptyState = document.getElementById('emptyState');
  const inputValue = document.getElementById('inputValue');
  const insertHeadBtn = document.getElementById('insertHead');
  const insertTailBtn = document.getElementById('insertTail');
  const deleteValueBtn = document.getElementById('deleteValue');
  const searchValueBtn = document.getElementById('searchValue');
  const clearAllBtn = document.getElementById('clearAll');

  // Helpers
  function setEmptyVisible(visible){
    emptyState.style.display = visible ? 'flex' : 'none';
  }

  function render(){
    // Clear canvas content
    // We'll render nodes left-to-right with arrows
    canvas.innerHTML = '';
    if(!head){
      canvas.appendChild(emptyState);
      setEmptyVisible(true);
      return;
    }
    setEmptyVisible(false);
    const row = document.createElement('div');
    row.className = 'list-row';
    canvas.appendChild(row);

    // Build array of nodes
    let curr = head;
    const nodes = [];
    while(curr){
      nodes.push(curr);
      curr = curr.next;
      // safety guard (shouldn't happen): break if too many nodes
      if(nodes.length > 1000) break;
    }

    nodes.forEach((n, idx) => {
      const nodeEl = document.createElement('div');
      nodeEl.className = 'node';
      nodeEl.dataset.id = n.id;

      const v = document.createElement('div');
      v.className = 'value';
      v.textContent = n.value;

      const meta = document.createElement('div');
      meta.className = 'meta';
      meta.textContent = (idx === 0 ? 'head' : '') + (idx === nodes.length-1 ? (idx===0? ' • tail' : 'tail') : '');

      nodeEl.appendChild(v);
      nodeEl.appendChild(meta);

      row.appendChild(nodeEl);

      if(idx < nodes.length - 1){
        const arrow = document.createElement('div');
        arrow.className = 'arrow';
        arrow.innerHTML = '&#8594;'; // right arrow
        row.appendChild(arrow);
      }
    });
    // scroll to show tail when inserting
    canvas.scrollLeft = canvas.scrollWidth;
  }

  // Basic list operations
  function insertHead(value){
    const newNode = makeNode(value);
    newNode.next = head;
    head = newNode;
    render();
    // small pop-in animation
    const el = canvas.querySelector(`.node[data-id="${newNode.id}"]`);
    if(el){
      el.style.transform = 'scale(0.9) translateY(-6px)';
      el.style.opacity = '0';
      requestAnimationFrame(()=> {
        el.style.transition = 'transform 260ms ease, opacity 260ms ease';
        el.style.transform = '';
        el.style.opacity = '';
        setTimeout(()=> el.style.transition = '', 300);
      });
    }
  }

  function insertTail(value){
    const newNode = makeNode(value);
    if(!head){
      head = newNode;
    } else {
      let cur = head;
      while(cur.next) cur = cur.next;
      cur.next = newNode;
    }
    render();
    const el = canvas.querySelector(`.node[data-id="${newNode.id}"]`);
    if(el){
      el.style.transform = 'translateY(6px) scale(0.98)';
      el.style.opacity = '0';
      requestAnimationFrame(()=> {
        el.style.transition = 'transform 300ms ease, opacity 300ms ease';
        el.style.transform = '';
        el.style.opacity = '';
        setTimeout(()=> el.style.transition = '', 350);
        canvas.scrollLeft = canvas.scrollWidth;
      });
    }
  }

  // Delete first node matching value. Returns true if deleted.
  function deleteValue(value, options = { animate:true }){
    if(!head) return false;
    const target = String(value);
    // special case head
    if(head.value === target){
      const removed = head;
      head = head.next;
      if(options.animate){
        animateRemoval(removed.id, ()=> render());
      } else {
        render();
      }
      return true;
    }
    // traverse to find previous
    let prev = head;
    let curr = head.next;
    let steps = 1;
    function stepAnimationPromise(){
      return new Promise(res=> setTimeout(res, 180));
    }
    const doSearch = async ()=>{
      while(curr){
        highlightNodeById(curr.id, 'searching');
        await stepAnimationPromise();
        if(curr.value === target){
          // remove
          prev.next = curr.next;
          if(options.animate){
            await animateRemoval(curr.id);
          }
          clearAllHighlights();
          render();
          return true;
        }
        // continue
        highlightNodeById(curr.id, '');
        prev = curr;
        curr = curr.next;
        steps++;
      }
      // not found
      clearAllHighlights();
      return false;
    };
    if(options.animate){
      // animate traversal starting from head.next
      // Highlight head briefly too
      const headEl = canvas.querySelector(`.node[data-id="${head.id}"]`);
      if(headEl){
        headEl.classList.add('searching');
      }
      setTimeout(()=> {
        if(headEl) headEl.classList.remove('searching');
      }, 180);
      return doSearch();
    } else {
      while(curr){
        if(curr.value === target){
          prev.next = curr.next;
          render();
          return true;
        }
        prev = curr;
        curr = curr.next;
      }
      return false;
    }
  }

  // Search: highlight traversal and mark found node when matched
  async function searchValue(value){
    clearAllHighlights();
    if(!head) return false;
    const target = String(value);
    let curr = head;
    while(curr){
      // highlight
      highlightNodeById(curr.id, 'searching');
      await new Promise(r=> setTimeout(r, 220));
      if(curr.value === target){
        highlightNodeById(curr.id, 'found');
        // leave highlight for a moment
        await new Promise(r=> setTimeout(r, 800));
        // keep found highlight briefly then clear
        // we keep it for UX, then clear
        clearAllHighlights();
        // re-render to ensure styles are consistent
        render();
        return true;
      }
      highlightNodeById(curr.id, '');
      curr = curr.next;
    }
    // not found - flash all nodes once
    const allNodes = Array.from(document.querySelectorAll('.node'));
    for(const el of allNodes){
      el.classList.add('searching');
    }
    await new Promise(r=> setTimeout(r, 380));
    for(const el of allNodes){
      el.classList.remove('searching');
    }
    return false;
  }

  // Visual helpers
  function highlightNodeById(id, cls){
    // cls: '', 'searching', 'found'
    const el = canvas.querySelector(`.node[data-id="${id}"]`);
    if(!el) return;
    el.classList.remove('searching','found');
    if(cls) el.classList.add(cls);
  }
  function clearAllHighlights(){
    const all = canvas.querySelectorAll('.node.searching, .node.found');
    all.forEach(el => el.classList.remove('searching','found'));
  }

  // Animate removal of DOM node with id; resolves after animation
  function animateRemoval(nodeId, cb){
    return new Promise((resolve)=>{
      const el = canvas.querySelector(`.node[data-id="${nodeId}"]`);
      if(!el){
        if(cb) cb();
        return resolve();
      }
      el.classList.add('removing');
      // also fade out adjacent arrow if present
      const nextSibling = el.nextElementSibling;
      if(nextSibling && nextSibling.classList.contains('arrow')){
        nextSibling.style.opacity = '0';
        nextSibling.style.transform = 'translateY(6px)';
      }
      setTimeout(()=> {
        if(cb) cb();
        resolve();
      }, 300);
    });
  }

  // Button wiring
  insertHeadBtn.addEventListener('click', ()=>{
    const v = inputValue.value.trim();
    if(v === '') { inputValue.focus(); return; }
    insertHead(v);
    inputValue.value = '';
    inputValue.focus();
  });
  insertTailBtn.addEventListener('click', ()=>{
    const v = inputValue.value.trim();
    if(v === '') { inputValue.focus(); return; }
    insertTail(v);
    inputValue.value = '';
    inputValue.focus();
  });
  deleteValueBtn.addEventListener('click', async ()=>{
    const v = inputValue.value.trim();
    if(v === '') { inputValue.focus(); return; }
    // if list empty, give small flash
    if(!head){
      flashEmpty();
      return;
    }
    // disable controls while animating
    toggleControls(true);
    const found = await deleteValue(v, { animate:true });
    toggleControls(false);
    if(!found){
      // brief not-found feedback: flash tail or empty state
      flashNotFound();
    }
    inputValue.value = '';
    inputValue.focus();
  });
  searchValueBtn.addEventListener('click', async ()=>{
    const v = inputValue.value.trim();
    if(v === '') { inputValue.focus(); return; }
    if(!head){
      flashEmpty();
      return;
    }
    toggleControls(true);
    const found = await searchValue(v);
    toggleControls(false);
    if(!found){
      // subtle not-found cue
      flashNotFound();
    }
    inputValue.value = '';
    inputValue.focus();
  });

  clearAllBtn.addEventListener('click', ()=>{
    if(!head){
      flashEmpty();
      return;
    }
    // quick confirmation
    if(!confirm('Clear the entire list?')) return;
    head = null;
    render();
  });

  function toggleControls(disable){
    [insertHeadBtn, insertTailBtn, deleteValueBtn, searchValueBtn, clearAllBtn, inputValue].forEach(el => {
      el.disabled = disable;
      if(disable){
        el.style.opacity = 0.6;
        el.style.pointerEvents = 'none';
      } else {
        el.style.opacity = '';
        el.style.pointerEvents = '';
      }
    });
  }

  function flashEmpty(){
    // flash the empty box if present
    emptyState.style.transition = 'transform 160ms ease, opacity 160ms ease';
    emptyState.style.transform = 'translateY(-6px)';
    emptyState.style.opacity = '0.8';
    setTimeout(()=> {
      emptyState.style.transform = '';
      emptyState.style.opacity = '';
      setTimeout(()=> emptyState.style.transition = '', 220);
    }, 160);
  }
  function flashNotFound(){
    // transient red border on canvas
    const old = canvas.style.boxShadow;
    canvas.style.boxShadow = '0 0 0 4px rgba(239,68,68,0.06)';
    setTimeout(()=> canvas.style.boxShadow = old, 520);
  }

  // initialize
  render();

  // keyboard: Enter to insert tail
  inputValue.addEventListener('keydown', (e)=>{
    if(e.key === 'Enter'){
      insertTailBtn.click();
    }
  });

  // Expose for console (for power users)
  window._sll = {
    get head(){ return head; },
    insertHead: v => { insertHead(v); },
    insertTail: v => { insertTail(v); },
    deleteValue: v => deleteValue(v, { animate:false }),
    clear: ()=> { head = null; render(); },
    render
  };

})();
</script>
</body>
</html>

