      g.appendChild(rect); g.appendChild(txt);
      content.appendChild(g);
      // ghost arrow to indicate empty pointer (dashed)
      const gx = x + NODE_W - PTR_W/2;
      const arrow = createSvg('line', {x1: gx, y1: y + NODE_H/2, x2: gx + 120, y2: y + NODE_H/2, class:'arrow ghostArrow'});
      content.appendChild(arrow);
      const nullTxt = createSvg('text', {x: gx + 126, y: y + NODE_H/2 + 5, class:'emptyMsg'});
      nullTxt.textContent = 'null';
      content.appendChild(nullTxt);
      status.textContent = 'List is empty.';
      return;
    }

    // Render each node with pointer box
    const nodePositions = [];
    let x = START_X;
    let y = START_Y;
    nodes.forEach((n,i) => {
      nodePositions.push({node:n,x:x,y:y});
      const g = createSvg('g', {class:'node', id:'node-' + n.id});
      // whole box: value region and pointer region on the right
      const rect = createSvg('rect', {x:x, y:y, width:NODE_W, height:NODE_H, rx:6, ry:6});
      g.appendChild(rect);
      // pointer sub-box overlay at right
      const ptrX = x + NODE_W - PTR_W;
      const pbox = createSvg('rect', {x:ptrX + 6, y:y + 8, width:PTR_W - 12, height:NODE_H - 16, class:'pointerBox'});
      g.appendChild(pbox);
      // value text
      const txt = createSvg('text', {x:x + 12, y: y + NODE_H/2 + 5, 'class':'value'});
      txt.textContent = String(n.value);
      g.appendChild(txt);

      // label for index (optional small)
      const idxTxt = createSvg('text', {x:x + NODE_W/2 - 8, y: y + NODE_H + 16, 'font-size':12, 'fill':'#666'});
      idxTxt.textContent = 'Node';
      g.appendChild(idxTxt);

      content.appendChild(g);
      x += NODE_W + GAP;
    });

    // Now draw arrows from each node's pointer to next node (or to null)
    nodePositions.forEach((p,i) => {
      const fromX = p.x + NODE_W - PTR_W/2;
      const fromY = p.y + NODE_H/2;
      if(p.node.next){
        // find target position
        const target = nodePositions.find(q => q.node === p.node.next);
        if(target){
          const toX = target.x + PTR_W/2; // point to left side of target
          const toY = target.y + NODE_H/2;
          // draw a smooth curve (cubic)
          const dx = Math.max(40, (toX - fromX) / 2);
          const pathD = `M ${fromX} ${fromY} C ${fromX + dx} ${fromY} ${toX - dx} ${toY} ${toX} ${toY}`;
          const path = createSvg('path', {d: pathD, class:'arrow'});
          content.appendChild(path);
        } else {
          // safety: point to some null position
          const toX = fromX + 80;
          const toY = fromY;
          const pathD = `M ${fromX} ${fromY} L ${toX} ${toY}`;
          const path = createSvg('path', {d: pathD, class:'arrow ghostArrow'});
          content.appendChild(path);
          const nullTxt = createSvg('text', {x: toX + 8, y: toY + 4, class:'emptyMsg'});
          nullTxt.textContent = 'null';
          content.appendChild(nullTxt);
        }
      } else {
        // points to null: draw a dashed line and "null"
        const toX = fromX + 80;
        const toY = fromY;
        const pathD = `M ${fromX} ${fromY} L ${toX} ${toY}`;
        const path = createSvg('path', {d: pathD, class:'arrow ghostArrow'});
        content.appendChild(path);
        const nullTxt = createSvg('text', {x: toX + 8, y: toY + 4, class:'emptyMsg'});
        nullTxt.textContent = 'null';
        content.appendChild(nullTxt);
      }
    });

    status.textContent = `List size: ${list.size}`;
  }

  function createSvg(tag, attrs){
    const el = document.createElementNS('http://www.w3.org/2000/svg', tag);
    for(const k in attrs){
      el.setAttribute(k, attrs[k]);
    }
    return el;
  }

  // Visual effects: highlight search path, flash deletion, etc.
  async function animateSearch(value){
    clearHighlights();
    if(list.size === 0){
      status.textContent = 'List is empty.';
      return;
    }
    let cur = list.head;
    let idx = 0;
    let found = null;
    while(cur){
      const nodeEl = document.getElementById('node-' + cur.id);
      if(nodeEl){
        nodeEl.classList.add('highlight');
        await sleep(350);
      }
      if(same(cur.value, value)){
        found = {node:cur, index: idx};
        if(nodeEl) nodeEl.classList.add('found');
        status.textContent = `Found value at index ${idx}.`;
        break;
      } else {
        if(nodeEl) nodeEl.classList.remove('highlight');
        idx++;
        cur = cur.next;
      }
    }
    if(!found){
      status.textContent = 'Value not found.';
    }
    // leave found highlighted for a short while
    await sleep(900);
    // clear only the transient highlight, keep 'found' green border for a bit shorter, then reset
    document.querySelectorAll('.node.highlight').forEach(n => n.classList.remove('highlight'));
    document.querySelectorAll('.node.found').forEach((el, i) => {
      // fade out the found highlight after a moment
      setTimeout(()=> el.classList.remove('found'), 600 + i*80);
    });
  }

  async function animateInsert(node, atHead){
    render(); // ensure node exists in DOM
    const nodeEl = document.getElementById('node-' + node.id);
    if(nodeEl){
      nodeEl.classList.add('highlight');
      await sleep(700);
      nodeEl.classList.remove('highlight');
    }
    status.textContent = `Inserted "${node.value}" ${atHead ? 'at head' : 'at tail'}. List size: ${list.size}`;
    render();
  }

  async function animateDelete(removed){
    if(!removed) return;
    // render then find the element
    render();
    const el = document.getElementById('node-' + removed.id);
    if(el){
      el.classList.add('deleted');
      status.textContent = `Deleted "${removed.value}".`;
      await sleep(400);
      // physically re-render to remove it
      render();
    } else {
      status.textContent = `Deleted "${removed.value}".`;
      render();
    }
  }

  function clearHighlights(){
    document.querySelectorAll('.node.highlight').forEach(n => n.classList.remove('highlight'));
    document.querySelectorAll('.node.found').forEach(n => n.classList.remove('found'));
  }

  function sleep(ms){ return new Promise(res => setTimeout(res, ms)); }

  // Button handlers
  insertHeadBtn.addEventListener('click', async () => {
    const v = valueInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to insert.';
      return;
    }
    const node = list.insertHead(parseValue(v));
    await animateInsert(node, true);
  });

  insertTailBtn.addEventListener('click', async () => {
    const v = valueInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to insert.';
      return;
    }
    const node = list.insertTail(parseValue(v));
    await animateInsert(node, false);
  });

  deleteBtn.addEventListener('click', async () => {
    const v = delInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to delete.';
      return;
    }
    const removed = list.deleteByValue(parseValue(v));
    if(!removed){
      status.textContent = 'Value not found; nothing deleted.';
      render();
      return;
    }
    await animateDelete(removed);
  });

  searchBtn.addEventListener('click', async () => {
    const v = searchInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to search.';
      return;
    }
    await animateSearch(parseValue(v));
  });

  clearBtn.addEventListener('click', () => {
    list.clear();
    render();
    status.textContent = 'Cleared list.';
  });

  // helper parse input to number if numeric
  function parseValue(s){
    if(s.trim() === '') return s;
    if(!isNaN(s) && s.trim() !== '') {
      // keep numeric format but allow leading zeros to remain string? We'll convert to number
      return Number(s);
    }
    return s;
  }

  // initial demo content
  (function seed(){
    list.insertTail(10);
    list.insertTail(20);
    list.insertTail(30);
    render();
    status.textContent = 'Demo list created. Try operations.';
  })();

  // make the svg viewBox width adjust based on nodes to avoid cramped layout
  const observer = new MutationObserver(() => {
    // compute width needed
    const nodes = list.toArray();
    const w = Math.max(400, START_X + (nodes.length) * (NODE_W + GAP) + 160);
    svg.setAttribute('viewBox', `0 0 ${w} 220`);
  });
  observer.observe(content, {childList:true, subtree:true});

  // keyboard Enter handling
  valueInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') insertTailBtn.click(); });
  delInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') deleteBtn.click(); });
  searchInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') searchBtn.click(); });

})();
</script>

</body>
</html>

Below is a single self-contained HTML file. Save it as something like linked_list_viz.html and open it in a browser. It implements a singly linked list visualization with real node boxes, SVG arrows connecting nodes (they update and animate), and controls for insert at head, insert at tail, delete by value, and search (with highlighting). It handles the empty-list case, including showing an empty-list placeholder. Code is fully client-side, no libraries required.

Features:
- Visual nodes are DIV boxes laid out horizontally; arrows are SVG paths connecting node centers.
- Insert at head / tail update layout and arrows smoothly.
- Delete by value removes the first matching node; handles deleting head, tail, only node, or non-existent value.
- Search highlights matches and scrolls them into view.
- Small animations for node insertion / removal.
- Handles values as plain text; trimming applied.

Here is the file content — copy everything into an .html file:

<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<title>Linked List Visualizer</title>
<meta name="viewport" content="width=device-width,initial-scale=1" />
<style>
  :root{
    --bg:#f6f8fa;
    --card:#ffffff;
    --accent:#2b8aef;
    --muted:#6b7280;
    --node-bg:#fffefc;
    --node-border:#d1d5db;
    --node-shadow: 0 2px 6px rgba(16,24,40,0.08);
    --highlight:#fff2a8;
  }
  html,body{height:100%;margin:0;font-family:Inter,Segoe UI,Roboto,Arial,sans-serif;background:var(--bg);color:#111827}
  .app{
    max-width:1000px;margin:28px auto;padding:20px;
  }
  header{display:flex;align-items:center;gap:14px;margin-bottom:18px}
  h1{font-size:20px;margin:0}
  .controls{
    display:flex;gap:12px;flex-wrap:wrap;margin-bottom:18px;align-items:center;
  }
  .controls input[type="text"]{
    padding:8px 10px;border:1px solid #d1d5db;border-radius:8px;background:#fff;min-width:140px;
  }
  .controls button{
    padding:8px 12px;border-radius:8px;border:1px solid transparent;background:var(--accent);color:#fff;cursor:pointer;
    box-shadow: 0 1px 0 rgba(0,0,0,0.05);
  }
  .controls button.ghost{
    background:transparent;color:var(--accent);border-color:var(--accent);
  }
  .controls label{color:var(--muted);font-size:13px;margin-right:6px}
  .canvas{
    position:relative;background:linear-gradient(180deg,#fff,#fcfdff);border-radius:12px;padding:18px;min-height:180px;
    border:1px solid #e6edf6;box-shadow: var(--node-shadow);
    overflow:auto;
  }
  .list-row{
    display:flex;align-items:center;padding:6px;gap:18px;min-height:140px;position:relative;
  }
  .node{
    display:flex;flex-direction:column;align-items:stretch;gap:6px;padding:10px;border-radius:8px;
    min-width:84px;background:var(--node-bg);border:1px solid var(--node-border);box-shadow:var(--node-shadow);
    transition:transform .22s ease, opacity .18s ease, box-shadow .18s ease;
    position:relative;z-index:2;
  }
  .node .val{font-weight:600;text-align:center;font-size:15px;color:#0f172a}
  .node .meta{text-align:center;font-size:12px;color:var(--muted)}
  .node.head-label::before{
    content:"HEAD";position:absolute;top:-12px;left:8px;background:var(--accent);color:white;padding:2px 6px;border-radius:6px;font-size:11px;
  }
  .node.tail-label::before{
    content:"TAIL";position:absolute;top:-12px;right:8px;background:#10b981;color:white;padding:2px 6px;border-radius:6px;font-size:11px;
  }
  .node.snappable{cursor:grab;}
  .node.highlight{
    background:linear-gradient(90deg,var(--highlight),#fff);box-shadow:0 4px 14px rgba(59,130,246,0.12);
  }
  .empty-placeholder{color:var(--muted);font-size:15px;padding:36px;text-align:center;border:2px dashed #e6edf6;border-radius:8px;background:linear-gradient(180deg,#fff,#fbfdff)}
  svg.arrows{position:absolute;left:0;top:0;width:100%;height:100%;pointer-events:none;overflow:visible}
  .msg{margin-top:12px;color:var(--muted);font-size:13px}
  .small{font-size:13px;color:var(--muted)}
  .controls-row{display:flex;gap:8px;align-items:center}
  /* small responsive */
  @media (max-width:640px){
    .list-row{gap:12px;min-height:120px}
    .node{min-width:72px;padding:8px}
  }
</style>
</head>
<body>
<div class="app">
  <header>
    <h1>Linked List Visualizer (Singly)</h1>
    <div class="small">Insert / Delete / Search with working arrows and empty-list handling</div>
  </header>

  <div class="controls" aria-hidden="false">
    <div class="controls-row">
      <label for="valueHead">Value</label>
      <input id="valueHead" type="text" placeholder="value to insert/delete/search" />
      <button id="insertHead">Insert at head</button>
      <button id="insertTail" class="ghost">Insert at tail</button>
    </div>

    <div class="controls-row">
      <button id="deleteVal">Delete by value</button>
      <button id="searchVal">Search</button>
      <button id="clearSearch" class="ghost">Clear search</button>
    </div>
    <div style="margin-left:auto" class="small">Nodes animated; arrows update automatically</div>
  </div>

  <div class="canvas" id="canvas" tabindex="0">
    <svg class="arrows" id="arrows"></svg>
    <div class="list-row" id="listRow">
      <div class="empty-placeholder" id="emptyPlaceholder">List is empty. Insert nodes to get started.</div>
    </div>
  </div>

  <div class="msg" id="message">Tip: Try inserting "A", "B", "C" and then delete or search values.</div>
</div>

<script>
(function(){
  // Data structure representing the nodes
  let nodes = []; // each node: {id, value}
  let idCounter = 1;

  const listRow = document.getElementById('listRow');
  const arrowsSvg = document.getElementById('arrows');
  const emptyPlaceholder = document.getElementById('emptyPlaceholder');
  const message = document.getElementById('message');

  const inputValue = document.getElementById('valueHead');
  const btnInsertHead = document.getElementById('insertHead');
  const btnInsertTail = document.getElementById('insertTail');
  const btnDeleteVal = document.getElementById('deleteVal');
  const btnSearchVal = document.getElementById('searchVal');
  const btnClearSearch = document.getElementById('clearSearch');
  const canvas = document.getElementById('canvas');

  function showMessage(text, timeout=2500){
    message.textContent = text;
    if(timeout>0){
      clearTimeout(showMessage._t);
      showMessage._t = setTimeout(()=> message.textContent = '','timeout');
    }
  }

  function createNodeElement(node){
    const el = document.createElement('div');
    el.className = 'node snappable';
    el.dataset.id = node.id;
    el.style.opacity = '0';
    el.style.transform = 'translateY(-8px) scale(.98)';
    el.innerHTML = `<div class="val">${escapeHtml(node.value)}</div><div class="meta">next -></div>`;
    requestAnimationFrame(()=>{
      el.style.transition = 'transform .28s ease, opacity .22s ease';
      el.style.opacity = '1';
      el.style.transform = 'translateY(0) scale(1)';
    });
    return el;
  }

  function escapeHtml(s){
    return String(s).replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;');
  }

  function render(){
    // Clear and re-render nodes
    // Keep focus and scroll position reasonable
    while(listRow.firstChild) listRow.removeChild(listRow.firstChild);

    if(nodes.length === 0){
      listRow.appendChild(emptyPlaceholder);
      drawArrows(); // clear
      return;
    }

    // create container for node elements
    for(let i=0;i<nodes.length;i++){
      const node = nodes[i];
      const el = createNodeElement(node);
      if(i===0) el.classList.add('head-label');
      if(i===nodes.length-1) el.classList.add('tail-label');
      listRow.appendChild(el);
    }

    // force layout then draw arrows
    requestAnimationFrame(()=> {
      drawArrows();
      // scroll newly added into view (if appended)
      const lastEl = listRow.querySelector('.node:last-child');
      if(lastEl) lastEl.scrollIntoView({behavior:'smooth',inline:'center'});
    });
  }

  function drawArrows(){
    // Recompute SVG arrow paths between nodes
    arrowsSvg.innerHTML = ''; // clear
    const nodesEls = Array.from(listRow.querySelectorAll('.node'));
    const canvasRect = canvas.getBoundingClientRect();
    if(nodesEls.length === 0) return;

    nodesEls.forEach((el,i)=>{
      if(i === nodesEls.length-1) return; // no next arrow from tail
      const startRect = el.getBoundingClientRect();
      const endRect = nodesEls[i+1].getBoundingClientRect();

      // compute points relative to svg (which is positioned at top-left of canvas)
      const svgRect = arrowsSvg.getBoundingClientRect();
      const startX = (startRect.right - svgRect.left);
      const startY = (startRect.top + startRect.bottom)/2 - svgRect.top;
      const endX = (endRect.left - svgRect.left);
      const endY = (endRect.top + endRect.bottom)/2 - svgRect.top;

      // draw a cubic bezier arrow that bends between nodes
      const dx = Math.max(24, (endX - startX) * 0.5);
      const path = document.createElementNS("http://www.w3.org/2000/svg","path");
      const d = `M ${startX} ${startY} C ${startX + dx} ${startY} ${endX - dx} ${endY} ${endX} ${endY}`;
      path.setAttribute('d', d);
      path.setAttribute('fill','none');
      path.setAttribute('stroke','#9ca3af');
      path.setAttribute('stroke-width','2');
      path.setAttribute('marker-end','url(#arrowhead)');
      path.setAttribute('opacity','0');
      path.style.transition = 'opacity .28s ease';
      arrowsSvg.appendChild(path);
      // fade in
      requestAnimationFrame(()=> path.setAttribute('opacity','1'));
    });

    // ensure arrowhead marker exists
    if(!arrowsSvg.querySelector('#marker-arrow')){
      const defs = document.createElementNS("http://www.w3.org/2000/svg","defs");
      defs.innerHTML = `
        <marker id="marker-arrow" viewBox="0 0 10 10" refX="9" refY="5" markerUnits="strokeWidth" markerWidth="8" markerHeight="8" orient="auto">
          <path d="M 0 0 L 10 5 L 0 10 z" fill="#6b7280"></path>
        </marker>
      `;
      arrowsSvg.appendChild(defs);
      // associate id used above
      // adjust existing paths to use the new id
      Array.from(arrowsSvg.querySelectorAll('path')).forEach(p => p.setAttribute('marker-end','url(#marker-arrow)'));
    } else {
      // ensure marker-end present
      Array.from(arrowsSvg.querySelectorAll('path')).forEach(p => p.setAttribute('marker-end','url(#marker-arrow)'));
    }
  }

  // Basic linked list operations
  function insertAtHead(value){
    const node = {id: idCounter++, value};
    nodes.unshift(node);
    render();
    showMessage(`Inserted "${value}" at head`);
  }

  function insertAtTail(value){
    const node = {id: idCounter++, value};
    nodes.push(node);
    render();
    showMessage(`Inserted "${value}" at tail`);
  }

  function deleteByValue(value){
    if(nodes.length === 0){
      showMessage('List is already empty');
      return;
    }
    const idx = nodes.findIndex(n => n.value === value);
    if(idx === -1){
      showMessage(`Value "${value}" not found`);
      return;
    }
    // animate removal
    const el = listRow.querySelector(`.node[data-id="${nodes[idx].id}"]`);
    if(el){
      el.style.transition = 'transform .22s ease, opacity .18s ease';
      el.style.transform = 'translateY(-8px) scale(.98)';
      el.style.opacity = '0';
      // remove after animation
      setTimeout(()=>{
        nodes.splice(idx,1);
        render();
      },220);
    } else {
      nodes.splice(idx,1);
      render();
    }
    showMessage(`Deleted first "${value}"`);
  }

  function searchValue(value){
    clearHighlights();
    if(nodes.length === 0){
      showMessage('List is empty');
      return;
    }
    const matches = nodes.filter(n => n.value === value).map(n => n.id);
    if(matches.length === 0){
      showMessage(`"${value}" not found`);
      return;
    }
    // highlight matching nodes
    matches.forEach(id => {
      const el = listRow.querySelector(`.node[data-id="${id}"]`);
      if(el){
        el.classList.add('highlight');
      }
    });
    // Focus on first match
    const firstEl = listRow.querySelector(`.node[data-id="${matches[0]}"]`);
    if(firstEl){
      firstEl.scrollIntoView({behavior:'smooth',inline:'center'});
      // brief pulse
      firstEl.animate([{boxShadow:'0 0 0 rgba(0,0,0,0)'},{boxShadow:'0 8px 30px rgba(59,130,246,0.12)'}],{duration:350,iterations:1,fill:'none'});
    }
    showMessage(`Found ${matches.length} node(s) matching "${value}"`);
  }

  function clearHighlights(){
    listRow.querySelectorAll('.node.highlight').forEach(n => n.classList.remove('highlight'));
    showMessage('Search cleared',1200);
  }

  // Wire up controls
  btnInsertHead.addEventListener('click', ()=> {
    const raw = inputValue.value.trim();
    if(raw === '') { showMessage('Please enter a non-empty value'); return; }
    insertAtHead(raw);
    inputValue.value = '';
    inputValue.focus();
  });
  btnInsertTail.addEventListener('click', ()=> {
    const raw = inputValue.value.trim();
    if(raw === '') { showMessage('Please enter a non-empty value'); return; }
    insertAtTail(raw);
    inputValue.value = '';
    inputValue.focus();
  });
  btnDeleteVal.addEventListener('click', ()=> {
    const raw = inputValue.value.trim();
    if(raw === '') { showMessage('Please enter a value to delete'); return; }
    deleteByValue(raw);
    inputValue.value = '';
    inputValue.focus();
  });
  btnSearchVal.addEventListener('click', ()=> {
    const raw = inputValue.value.trim();
    if(raw === '') { showMessage('Please enter a value to search'); return; }
    searchValue(raw);
  });
  btnClearSearch.addEventListener('click', ()=> {
    clearHighlights();
    inputValue.focus();
  });

  // Resize observer to redraw arrows when layout changes
  const ro = new ResizeObserver(()=> drawArrows());
  ro.observe(canvas);
  ro.observe(listRow);

  // window resize redraw
  window.addEventListener('resize', drawArrows);

  // keyboard shortcuts
  inputValue.addEventListener('keydown', (e)=>{
    if(e.key === 'Enter'){
      if(e.shiftKey) btnInsertTail.click();
      else btnInsertHead.click();
    }
  });

  // initial render
  render();

  // Simple drag-to-reorder (optional nice-to-have)
  // Implement basic drag to reorder nodes horizontally
  let dragState = null;
  listRow.addEventListener('mousedown', (e)=>{
    const nodeEl = e.target.closest('.node');
    if(!nodeEl) return;
    dragState = {
      el: nodeEl,
      startX: e.clientX,
      origRect: nodeEl.getBoundingClientRect(),
      id: Number(nodeEl.dataset.id),
      placeholder: null,
    };
    nodeEl.style.cursor = 'grabbing';
    nodeEl.style.zIndex = 999;
    nodeEl.style.transition = 'none';
    nodeEl.style.boxShadow = '0 10px 30px rgba(16,24,40,0.12)';
    dragState.offsetX = e.clientX - dragState.origRect.left;
    document.addEventListener('mousemove', onDrag);
    document.addEventListener('mouseup', onDrop);
    e.preventDefault();
  });

  function onDrag(e){
    if(!dragState) return;
    const el = dragState.el;
    const dx = e.clientX - dragState.startX;
    el.style.transform = `translateX(${dx}px) translateY(-6px)`;
    // Determine new index by center x
    const nodesEls = Array.from(listRow.querySelectorAll('.node')).filter(n => n !== el);
    const centerX = e.clientX;
    let insertBefore = null;
    for(const other of nodesEls){
      const r = other.getBoundingClientRect();
      if(centerX < r.left + r.width/2){
        insertBefore = other;
        break;
      }
    }
    // move DOM placeholder
    if(insertBefore){
      listRow.insertBefore(el, insertBefore);
    } else {
      listRow.appendChild(el);
    }
    drawArrows();
  }

  function onDrop(e){
    if(!dragState) return;
    const el = dragState.el;
    el.style.transition = 'transform .22s ease, box-shadow .18s ease';
    el.style.transform = 'translateX(0) translateY(0)';
    el.style.zIndex = '';
    el.style.cursor = 'grab';
    el.style.boxShadow = '';
    // Rebuild nodes array to reflect new DOM order
    const newOrderIds = Array.from(listRow.querySelectorAll('.node')).map(n => Number(n.dataset.id));
    // Update nodes to match order (values preserved)
    nodes = newOrderIds.map(id => nodes.find(n => n.id === id));
    render();
    document.removeEventListener('mousemove', onDrag);
    document.removeEventListener('mouseup', onDrop);
    dragState = null;
  }

  // Touch support for drag
  listRow.addEventListener('touchstart', (e)=>{
    const touch = e.touches[0];
    const nodeEl = e.target.closest('.node');
    if(!nodeEl) return;
    dragState = {
      el: nodeEl,
      startX: touch.clientX,
      origRect: nodeEl.getBoundingClientRect(),
      id: Number(nodeEl.dataset.id),
    };
    nodeEl.style.cursor = 'grabbing';
    nodeEl.style.zIndex = 999;
    nodeEl.style.transition = 'none';
    nodeEl.style.boxShadow = '0 10px 30px rgba(16,24,40,0.12)';
    dragState.offsetX = touch.clientX - dragState.origRect.left;
    document.addEventListener('touchmove', onTouchDrag,{passive:false});
    document.addEventListener('touchend', onTouchDrop);
  }, {passive:false});

  function onTouchDrag(e){
    e.preventDefault();
    const touch = e.touches[0];
    if(!dragState) return;
    const el = dragState.el;
    const dx = touch.clientX - dragState.startX;
    el.style.transform = `translateX(${dx}px) translateY(-6px)`;
    const nodesEls = Array.from(listRow.querySelectorAll('.node')).filter(n => n !== el);
    const centerX = touch.clientX;
    let insertBefore = null;
    for(const other of nodesEls){
      const r = other.getBoundingClientRect();
