        insertBefore = other;
        break;
      }
    }
    if(insertBefore){
      listRow.insertBefore(el, insertBefore);
    } else {
      listRow.appendChild(el);
    }
    drawArrows();
  }

  function onTouchDrop(e){
    if(!dragState) return;
    const el = dragState.el;
    el.style.transition = 'transform .22s ease, box-shadow .18s ease';
    el.style.transform = 'translateX(0) translateY(0)';
    el.style.zIndex = '';
    el.style.cursor = 'grab';
    el.style.boxShadow = '';
    const newOrderIds = Array.from(listRow.querySelectorAll('.node')).map(n => Number(n.dataset.id));
    nodes = newOrderIds.map(id => nodes.find(n => n.id === id));
    render();
    document.removeEventListener('touchmove', onTouchDrag);
    document.removeEventListener('touchend', onTouchDrop);
    dragState = null;
  }

})();
