<body>
<div class="container" role="application" aria-label="Singly linked list visualizer">
  <h1>Singly Linked List Visualizer</h1>

  <div class="controls" aria-hidden="false">
    <input id="valueInput" type="text" placeholder="Value (text or number)" aria-label="Value input" />
    <div class="btn-row">
      <button id="insertHead" class="primary" title="Insert at head">Insert at head</button>
      <button id="insertTail" class="primary" title="Insert at tail">Insert at tail</button>
      <button id="deleteBtn" class="warn" title="Delete first node with value">Delete by value</button>
      <button id="searchBtn" title="Search for value">Search</button>
    </div>
    <div style="flex:1"></div>
    <div class="small">Nodes: <span id="count">0</span></div>
  </div>

  <div class="board" id="board" tabindex="0" aria-live="polite">
    <svg class="svg-layer" id="svgLayer" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMinYMin meet"></svg>
    <div class="nodes" id="nodesContainer" role="list" aria-label="Linked list nodes">
      <div class="empty-state" id="emptyState">
        <div style="font-size:22px; color:var(--muted)">Empty list</div>
        <div class="small">Insert at head or tail to add nodes</div>
      </div>
    </div>
  </div>

  <div class="legend">
    <div class="label">Green = found</div>
    <div class="label">Arrows show next pointers</div>
  </div>

  <footer>
    <div class="small">Drag to scroll horizontally. Smooth animations. Handles empty list.</div>
    <div class="small">Built-in demo</div>
  </footer>
