<script>
(function(){
  // Data structure
  class Node {
    constructor(value){
      this.value = value;
      this.next = null;
    }
  }
  class SinglyLinkedList {
    constructor(){ this.head = null; this.size = 0; }
    insertHead(value){
      const n = new Node(value);
      n.next = this.head;
      this.head = n;
      this.size++;
      return n;
    }
    insertTail(value){
      const n = new Node(value);
      if(!this.head){ this.head = n; this.size++; return n; }
      let cur = this.head;
      while(cur.next) cur = cur.next;
      cur.next = n;
      this.size++;
      return n;
    }
    deleteByValue(value){
      if(!this.head) return null;
      if(this.head.value === value){
        const removed = this.head;
        this.head = this.head.next;
        removed.next = null;
        this.size--;
        return removed;
      }
      let prev = this.head;
      let cur = this.head.next;
      while(cur){
        if(cur.value === value){
          prev.next = cur.next;
          cur.next = null;
          this.size--;
          return cur;
        }
        prev = cur; cur = cur.next;
      }
      return null;
    }
    find(value){
      let idx = 0;
      let cur = this.head;
      while(cur){
        if(cur.value === value) return {node:cur, index:idx};
        cur = cur.next; idx++;
      }
      return null;
    }
    toArray(){
      const arr = [];
      let cur = this.head;
      while(cur){ arr.push(cur); cur = cur.next; }
      return arr;
    }
  }

  // UI
  const list = new SinglyLinkedList();
  const nodesContainer = document.getElementById('nodesContainer');
  const svgLayer = document.getElementById('svgLayer');
  const emptyState = document.getElementById('emptyState');
  const countEl = document.getElementById('count');
  const valueInput = document.getElementById('valueInput');
  const insertHeadBtn = document.getElementById('insertHead');
  const insertTailBtn = document.getElementById('insertTail');
  const deleteBtn = document.getElementById('deleteBtn');
  const searchBtn = document.getElementById('searchBtn');
  let animating = false;

  function updateCount(){ countEl.textContent = list.size; }

  // Render nodes as DOM elements, but maintain mapping from Node objects to DOM elements
  const nodeToElem = new Map();

  function createNodeElem(node){
    const el = document.createElement('div');
    el.className = 'node adding';
    el.setAttribute('role','listitem');
    const valueDiv = document.createElement('div');
    valueDiv.className = 'value';
    valueDiv.textContent = String(node.value);
    const ptrDiv = document.createElement('div');
    ptrDiv.className = 'pointer';
    ptrDiv.textContent = 'next';
    el.appendChild(valueDiv);
    el.appendChild(ptrDiv);
    nodeToElem.set(node, el);
    return el;
  }

  function refreshView(){
    // Clear SVG
    while(svgLayer.firstChild) svgLayer.removeChild(svgLayer.firstChild);

    const arr = list.toArray();

    updateCount();

    // Handle empty
    if(arr.length === 0){
      emptyState.style.display = 'flex';
      nodesContainer.style.justifyContent = 'center';
      return;
    } else {
      emptyState.style.display = 'none';
      nodesContainer.style.justifyContent = 'flex-start';
    }

    // Ensure DOM elements exist in same order
    // Remove any elements that no longer correspond
    const existing = Array.from(nodesContainer.querySelectorAll('.node'));
    const existingNodes = existing.map(e=>{
      for(const [node,el] of nodeToElem.entries()){
        if(el === e) return node;
      }
      return null;
    });

    // Rebuild container: keep existing elements in order, create new where needed
    nodesContainer.querySelectorAll('.node').forEach(n => nodesContainer.removeChild(n));
    arr.forEach(node=>{
      let el = nodeToElem.get(node);
      if(!el){
        el = createNodeElem(node);
      } else {
        el.classList.remove('removing');
        el.classList.remove('adding');
        el.classList.remove('highlight');
        el.classList.remove('found');
        // update text in case value changed
        const val = el.querySelector('.value');
        if(val) val.textContent = String(node.value);
      }
      nodesContainer.appendChild(el);
    });

    // After layout, draw arrows
    requestAnimationFrame(drawArrows);
  }

  function drawArrows(){
    // Resize svg to match board content
    const boardRect = nodesContainer.getBoundingClientRect();
    svgLayer.setAttribute('width', boardRect.width);
    svgLayer.setAttribute('height', boardRect.height);

    // For each node, draw arrow from its right edge to next node's left edge (center vertically)
    const arr = list.toArray();
    for(let i=0;i<arr.length;i++){
      const node = arr[i];
      const el = nodeToElem.get(node);
      if(!el) continue;
      const rect = el.getBoundingClientRect();
      const containerRect = nodesContainer.getBoundingClientRect();

      // Coordinates relative to svg layer
      const startX = rect.right - containerRect.left - 8; // a little inset
      const startY = rect.top - containerRect.top + rect.height/2;

      if(node.next){
        const nextEl = nodeToElem.get(node.next);
        if(!nextEl) continue;
        const rect2 = nextEl.getBoundingClientRect();
        const endX = rect2.left - containerRect.left + 8;
        const endY = rect2.top - containerRect.top + rect2.height/2;

        // Create a curved path
        const dx = Math.max(24, Math.abs(endX - startX) * 0.4);
        const path = document.createElementNS('http://www.w3.org/2000/svg','path');
        const d = `M ${startX} ${startY} C ${startX + dx} ${startY} ${endX - dx} ${endY} ${endX} ${endY}`;
        path.setAttribute('d', d);
        path.setAttribute('fill','none');
        path.setAttribute('stroke','#94a3b8');
        path.setAttribute('stroke-width','2');
        path.setAttribute('stroke-linecap','round');
        svgLayer.appendChild(path);

        // Arrowhead
        const arrow = document.createElementNS('http://www.w3.org/2000/svg','path');
        const size = 8;
        const angle = Math.atan2(endY - (endY), endX - endX); // dummy to satisfy; we'll set marker instead
        // Use marker approach for crisp arrowheads
        // create marker once
      } else {
        // draw null box or slash
        const rectEl = document.createElementNS('http://www.w3.org/2000/svg','rect');
        const boxW = 16, boxH = 10;
        rectEl.setAttribute('x', startX + 6);
        rectEl.setAttribute('y', startY - boxH/2);
        rectEl.setAttribute('width', boxW);
        rectEl.setAttribute('height', boxH);
        rectEl.setAttribute('rx',2);
        rectEl.setAttribute('ry',2);
        rectEl.setAttribute('fill','rgba(255,255,255,0.03)');
        rectEl.setAttribute('stroke','#94a3b8');
        rectEl.setAttribute('stroke-width','1.2');
        svgLayer.appendChild(rectEl);

        // small slash to indicate null
        const line = document.createElementNS('http://www.w3.org/2000/svg','line');
        line.setAttribute('x1', startX + 8);
        line.setAttribute('y1', startY - 3);
        line.setAttribute('x2', startX + 14);
        line.setAttribute('y2', startY + 3);
        line.setAttribute('stroke','#94a3b8');
        line.setAttribute('stroke-width','1.6');
        svgLayer.appendChild(line);
      }
    }

    // Add arrowhead marker and re-draw paths to use marker-end
    // (We add marker definition once)
    const defs = document.createElementNS('http://www.w3.org/2000/svg','defs');
    const marker = document.createElementNS('http://www.w3.org/2000/svg','marker');
    marker.setAttribute('id','arrowhead');
    marker.setAttribute('markerWidth','10');
    marker.setAttribute('markerHeight','10');
    marker.setAttribute('refX','6');
    marker.setAttribute('refY','5');
    marker.setAttribute('orient','auto');
    const mpath = document.createElementNS('http://www.w3.org/2000/svg','path');
    mpath.setAttribute('d','M 0 0 L 10 5 L 0 10 z');
    mpath.setAttribute('fill','#94a3b8');
    marker.appendChild(mpath);
    defs.appendChild(marker);
    svgLayer.appendChild(defs);

    // Replace earlier straight path strokes with marker-end usage:
    const paths = svgLayer.querySelectorAll('path');
    paths.forEach(p=>{
      if(p.getAttribute('d') && p.getAttribute('stroke') === '#94a3b8'){
        p.setAttribute('marker-end','url(#arrowhead)');
        p.setAttribute('stroke-width','2');
      }
    });
  }

  // Helpers
  function sanitizeInput(v){
    if(v === null || v === undefined) return '';
    let s = String(v).trim();
    return s;
  }

  // Actions
  insertHeadBtn.addEventListener('click', ()=>{
    if(animating) return;
    const v = sanitizeInput(valueInput.value);
    if(v === '') return flash(valueInput);
    animating = true;
    emptyState.style.display = 'none';
    const node = list.insertHead(v);
    const el = createNodeElem(node);
    nodesContainer.insertBefore(el, nodesContainer.querySelector('.node') || null);
    // animate and refresh
    setTimeout(()=>{ el.classList.remove('adding'); refreshView(); animating = false; }, 260);
  });

  insertTailBtn.addEventListener('click', ()=>{
    if(animating) return;
    const v = sanitizeInput(valueInput.value);
    if(v === '') return flash(valueInput);
    animating = true;
    emptyState.style.display = 'none';
    const node = list.insertTail(v);
    const el = createNodeElem(node);
    nodesContainer.appendChild(el);
    setTimeout(()=>{ el.classList.remove('adding'); refreshView(); animating = false; }, 260);
  });

  deleteBtn.addEventListener('click', ()=>{
    if(animating) return;
    const v = sanitizeInput(valueInput.value);
    if(v === '') return flash(valueInput);
    animating = true;
    // find node in list to delete visually
    const found = list.find(v);
    if(!found){
      animating = false;
      flash(valueInput, true);
      return;
    }
    const node = found.node;
    const el = nodeToElem.get(node);
    if(el){
      el.classList.add('removing');
      // after animation, mutate list
      setTimeout(()=>{
        list.deleteByValue(v);
        // remove element from DOM map
        if(el.parentNode) el.parentNode.removeChild(el);
        nodeToElem.delete(node);
        refreshView();
        animating = false;
      }, 220);
    } else {
      // fallback
      list.deleteByValue(v);
      refreshView();
      animating = false;
    }
  });

  searchBtn.addEventListener('click', ()=>{
    if(animating) return;
    const v = sanitizeInput(valueInput.value);
    if(v === '') return flash(valueInput);
    animating = true;
    // clear previous highlights
    nodesContainer.querySelectorAll('.node').forEach(n=> n.classList.remove('highlight','found'));
    // traverse with animation highlighting each node in order
    const arr = list.toArray();
    if(arr.length === 0){
      animating = false;
      flash(valueInput, true);
      return;
    }
    let i = 0;
    function step(){
      if(i > 0){
        const prevNode = arr[i-1];
        const prevEl = nodeToElem.get(prevNode);
        if(prevEl) prevEl.classList.remove('highlight');
      }
      if(i >= arr.length){
        animating = false;
        return;
      }
      const node = arr[i];
      const el = nodeToElem.get(node);
      if(el){
        el.classList.add('highlight');
        // if matched
        if(node.value === v){
          el.classList.add('found');
          // keep highlight briefly, then stop
          setTimeout(()=>{ animating = false; }, 600);
          // focus scroll into view
          el.scrollIntoView({behavior:'smooth', inline:'center', block:'nearest'});
          return;
        }
        // scroll into view
        el.scrollIntoView({behavior:'smooth', inline:'center', block:'nearest'});
      }
      i++;
      setTimeout(step, 420);
    }
    step();
  });

  // Small visual feedback for invalid input
  function flash(el, negative=false){
    const orig = el.style.boxShadow;
    el.style.transition = 'box-shadow .18s';
    el.style.boxShadow = negative ? '0 0 0 4px rgba(235,87,87,0.16)' : '0 0 0 4px rgba(96,165,250,0.12)';
    setTimeout(()=> el.style.boxShadow = orig, 420);
  }

  // Click node to delete quickly (optional)
  nodesContainer.addEventListener('click', (e)=>{
    const nodeEl = e.target.closest('.node');
    if(!nodeEl) return;
    // find corresponding node
    for(const [node,el] of nodeToElem.entries()){
      if(el === nodeEl){
        // prompt for delete confirmation
        const ok = confirm('Delete node with value "'+node.value+'"?');
        if(ok){
          // perform delete
          list.deleteByValue(node.value);
          if(nodeEl.parentNode) nodeEl.parentNode.removeChild(nodeEl);
          nodeToElem.delete(node);
          refreshView();
        }
        break;
      }
    }
  });

  // Resize observer to redraw arrows on layout changes
  const ro = new ResizeObserver(()=> drawArrows());
  ro.observe(nodesContainer);
  window.addEventListener('resize', ()=> drawArrows());

  // Keyboard: Enter to insert tail
  valueInput.addEventListener('keydown', (e)=>{
    if(e.key === 'Enter'){
      insertTailBtn.click();
    }
  });

  // initial demo content
  function seedDemo(){
    const demo = ['A','B','C'];
    demo.forEach((v,i)=>{
      setTimeout(()=>{ list.insertTail(v); refreshView(); }, i*140);
    });
    setTimeout(()=> refreshView(), 500);
  }
  seedDemo();

  // expose for debugging
  window._ll = list;

})();
</script>
</body>
</html>
```

Notes:
- The visualization uses DOM nodes for each list node and an SVG overlay for curved arrows and null boxes. This keeps arrows crisp and aligned.
